import { ContributionAuthorDetails } from './contribution.author.details';
import { ContributionType } from './contribution.type';

export type ContributionDocument = {
  /**
   * Id of the entity related to this report
   * e.g. whiteboardId, memoId, spaceId, etc.
   * It is not the id of the contribution document itself, which is generated by Elasticsearch.
   */
  id: string;
  /**
   * Contribution type, e.g. 'whiteboard created', 'memo.created', etc.
   */
  type: ContributionType;
  /**
   * Display name of the entity related to this report
   */
  name: string;
  /**
   * Timestamp
   */
  '@timestamp': Date;
  /**
   * Environment, obtained from the config hosting.environment
   */
  environment: string;
  /**
   * Identifier of the space this contribution belongs to.
   * If the contribution is related to a space itself,this will be the Level 0 space id.
   */
  space: string;
} & ContributionAuthorDetails;
